mapper.select:
SELECT COUNT(*)
FROM VW_COMMENT
WHERE USER_ID = #{userId}

mapper.update:
UPDATE TBL_COMMENT
SET COMMENT_CONTENT = #{commentContent}
WHERE ID = #{id} AND USER_ID = #{userId} AND COMMENT_IS_DELETED = 0

UPDATE TBL_COMMENT
SET COMMENT_IS_DELETED = 1
